function textCopied(){var t=window.getSelection().toString();if(console.log(t," copied"),-1===t.indexOf("oi.edav"))return t;var n=t.match(/oi\.edav@[\w\._\-]+/g);if(!n)return t;for(var e=0;e<n.length;e++){var o=n[e];t=t.replace(o,Array.from(o).reverse().join(""))}copyToClipboard(t)}function copyToClipboard(t){var n=document.createElement("textarea");n.textContent=t,n.style.position="fixed",document.body.appendChild(n),n.select();try{return document.execCommand("cut")}catch(t){return console.warn("Copy to clipboard failed.",t),!1}finally{document.body.removeChild(n)}}function initEMailLinks(){$('a[href^="mailto:"').each(function(){console.log($(this).text())})}function init(){initEMailLinks(),initMap(),document.oncopy=textCopied}window.addEventListener?window.addEventListener("load",init,!1):window.attachEvent?window.attachEvent("onload",init):window.onload=init;